  def initialize(size)
    @parent = Array(Int64).new(size) { |i| i.to_i64 }
    @rank = Array(Int64).new(size, 0_i64)
  end

  def find(u)
    if @parent[u] != u
      @parent[u] = find(@parent[u])
    end
    @parent[u]
  end

  def union(u, v)
    root_u = find(u)
    root_v = find(v)
    return false if root_u == root_v

    if @rank[root_u] > @rank[root_v]
      @parent[root_v] = root_u
    elsif @rank[root_u] < @rank[root_v]
      @parent[root_u] = root_v
    else
      @parent[root_v] = root_u
      @rank[root_u] += 1
    end
    true
  end
end

